import CoreImage
import CoreImage.CIFilterBuiltins
import UIKit
import SwiftUI

class ImageFilterService: ObservableObject {
    @Published var filteredImage: UIImage?
    private let context = CIContext()

    enum FilterType: String, CaseIterable, Identifiable {
        case original = "Original"
        case sepia = "Sepia"
        case noir = "B&W"
        case bloom = "Bloom"
        case vignette = "Vignette"
        case blur = "Blur"
        case sharpen = "Sharpen"

        var id: String { rawValue }
    }

    func apply(filter: FilterType, to image: UIImage, intensity: Float = 0.5) {
        guard let ciImage = CIImage(image: image) else { return }

        let output: CIImage?
        switch filter {
        case .original:
            output = ciImage
        case .sepia:
            let f = CIFilter.sepiaTone()
            f.inputImage = ciImage
            f.intensity = intensity
            output = f.outputImage
        case .noir:
            let f = CIFilter.photoEffectNoir()
            f.inputImage = ciImage
            output = f.outputImage
        case .bloom:
            let f = CIFilter.bloom()
            f.inputImage = ciImage
            f.intensity = intensity
            f.radius = 10
            output = f.outputImage
        case .vignette:
            let f = CIFilter.vignette()
            f.inputImage = ciImage
            f.intensity = intensity * 2
            f.radius = 1
            output = f.outputImage
        case .blur:
            let f = CIFilter.gaussianBlur()
            f.inputImage = ciImage
            f.radius = intensity * 20
            output = f.outputImage
        case .sharpen:
            let f = CIFilter.sharpenLuminance()
            f.inputImage = ciImage
            f.sharpness = intensity
            output = f.outputImage
        }

        guard let result = output,
              let cgImage = context.createCGImage(result, from: ciImage.extent) else {
            filteredImage = image
            return
        }
        filteredImage = UIImage(cgImage: cgImage)
    }
}
